import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "YACA - Yet Another Catalog Addon",
  description: "Configura il tuo addon Stremio personalizzato",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="it" className="dark">
      <head>
        <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&amp;display=swap" rel="stylesheet" />
        <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&amp;display=swap" rel="stylesheet" />
      </head>
      <body className="antialiased font-display bg-background-light dark:bg-background-dark text-slate-900 dark:text-slate-100 min-h-screen">
        <div className="relative flex h-auto min-h-screen w-full flex-col overflow-x-hidden">
          <div className="layout-container flex h-full grow flex-col">
            {children}
          </div>
        </div>
      </body>
    </html>
  );
}

'use client';
import { useState } from 'react';
import { Profile, Catalog, Preset } from '@/types';
import { CatalogItem } from '@/components/shared/CatalogItem';
import { MergeModal } from '@/components/modals/MergeModal';
import { Button } from '@/components/ui/button';
import { Layers } from 'lucide-react';

interface ActiveCatalogsPanelProps {
  profile: Profile;
  onReorder: (catalogs: Catalog[]) => void;
  onRemove: (catalogId: string) => void;
  onMerge: (catalog: Catalog) => void;
  presets: Preset[];
  myLists: Catalog[];
  onRemoveMyList: (id: string) => void;
}

export function ActiveCatalogsPanel({
  profile,
  onReorder,
  onRemove,
  onMerge,
  presets,
  myLists,
  onRemoveMyList,
}: ActiveCatalogsPanelProps) {
  const [dragIndex, setDragIndex] = useState<number | null>(null);
  const [mergeSource, setMergeSource] = useState<Catalog | null>(null);
  const [mergeTarget, setMergeTarget] = useState<Catalog | null>(null);
  const [showMergeModal, setShowMergeModal] = useState(false);
  const [hoverMergeIndex, setHoverMergeIndex] = useState<number | null>(null);
  const [hoverTimer, setHoverTimer] = useState<NodeJS.Timeout | null>(null);

  const presetMap = new Map(presets.map((preset) => [preset.id, preset]));
  const presetCatalogs: Catalog[] = profile.raw_ui_state.selectedPresets
    .map((presetId) => presetMap.get(presetId))
    .filter((preset): preset is Preset => Boolean(preset))
    .map((preset) => ({
      id: preset.id,
      name: preset.name,
      type: preset.type === 'series' ? 'series' : 'movie',
      source: 'preset',
      filters: preset.filters,
      emoji: preset.emoji,
    }));
  const allCatalogs = [...profile.existingCatalogs, ...presetCatalogs];
  const orderMap = new Map((profile.raw_ui_state.catalogOrder ?? []).map((id, i) => [id, i]));
  const catalogs = [...allCatalogs].sort((a, b) => {
    const aOrder = orderMap.get(a.id) ?? Number.MAX_SAFE_INTEGER;
    const bOrder = orderMap.get(b.id) ?? Number.MAX_SAFE_INTEGER;
    return aOrder - bOrder;
  });

  const handleDragStart = (index: number) => {
    setDragIndex(index);
  };

  const handleDrop = (targetIndex: number) => {
    if (dragIndex === null || dragIndex === targetIndex) return;
    const reordered = [...catalogs];
    const [moved] = reordered.splice(dragIndex, 1);

    // If dropped on same position or adjacent, reorder; if Shift held could merge
    reordered.splice(targetIndex, 0, moved);
    onReorder(reordered);
    setDragIndex(null);
  };

  const handleMergeDrop = (targetCatalog: Catalog, sourceCatalog: Catalog) => {
    setMergeSource(sourceCatalog);
    setMergeTarget(targetCatalog);
    setShowMergeModal(true);
  };

  const handleDragOverWithMerge = (
    e: React.DragEvent,
    targetIndex: number,
    targetCatalog: Catalog
  ) => {
    e.preventDefault();

    // Normal reorder if not holding over
    if (dragIndex === null || dragIndex === targetIndex) {
      if (hoverTimer) {
        clearTimeout(hoverTimer);
        setHoverTimer(null);
      }
      setHoverMergeIndex(null);
      return;
    }

    // Hover-to-merge logic
    if (hoverMergeIndex !== targetIndex) {
      if (hoverTimer) clearTimeout(hoverTimer);

      setHoverMergeIndex(targetIndex);
      const timer = setTimeout(() => {
        handleMergeDrop(targetCatalog, catalogs[dragIndex]);
        setHoverMergeIndex(null);
        setHoverTimer(null);
      }, 1000); // 1 second hold to merge

      setHoverTimer(timer);
    }

    if (e.shiftKey) {
      e.dataTransfer.dropEffect = 'copy';
    }
  };

  const handleDragLeave = () => {
    if (hoverTimer) {
      clearTimeout(hoverTimer);
      setHoverTimer(null);
    }
    setHoverMergeIndex(null);
  };

  const handleDropWithMerge = (e: React.DragEvent, targetIndex: number, targetCatalog: Catalog) => {
    if (hoverTimer) {
      clearTimeout(hoverTimer);
      setHoverTimer(null);
    }
    setHoverMergeIndex(null);

    if ((e.shiftKey || hoverMergeIndex === targetIndex) && dragIndex !== null && dragIndex !== targetIndex) {
      handleMergeDrop(targetCatalog, catalogs[dragIndex]);
    } else {
      handleDrop(targetIndex);
    }
    setDragIndex(null);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100">
          I tuoi Cataloghi ({catalogs.length})
        </h3>
        {catalogs.length > 1 && (
          <p className="text-xs text-slate-500 dark:text-slate-400">Trascina per riordinare &bull; Shift + trascina per unire</p>
        )}
      </div>

      {catalogs.length === 0 ? (
        <div className="rounded-xl border-2 border-dashed border-slate-200 dark:border-slate-700/50 p-12 text-center bg-slate-50 dark:bg-slate-800/20">
          <Layers className="mx-auto h-12 w-12 text-slate-400 dark:text-slate-500 mb-4" />
          <p className="text-base font-bold text-slate-900 dark:text-slate-100">Nessun catalogo attivo</p>
          <p className="text-sm text-slate-500 dark:text-slate-400 mt-2">Aggiungi cataloghi dalla sezione Esplora o creane uno nuovo.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 w-full">
          {catalogs.map((catalog, index) => (
            <CatalogItem
              key={catalog.id}
              catalog={catalog}
              isDragging={dragIndex === index}
              isMergeTarget={hoverMergeIndex === index}
              onRemove={() => onRemove(catalog.id)}
              onDragStart={() => handleDragStart(index)}
              onDragOver={(e) => handleDragOverWithMerge(e, index, catalog)}
              onDragLeave={handleDragLeave}
              onDrop={(e) => handleDropWithMerge(e, index, catalog)}
              onDragEnd={() => {
                setDragIndex(null);
                handleDragLeave();
              }}
            />
          ))}
        </div>
      )}

      {/* My Lists */}
      {myLists.length > 0 && (
        <div className="pt-8 border-t border-slate-200 dark:border-slate-700/50">
          <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-4">
            Le Mie Liste ({myLists.length})
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 w-full">
            {myLists.map((catalog, index) => (
              <CatalogItem
                key={catalog.id}
                catalog={catalog}
                onRemove={() => onRemoveMyList(catalog.id)}
                isMergeTarget={hoverMergeIndex === index + 1000} // Offset for myLists
                onDragStart={() => setDragIndex(index + 1000)}
                onDragOver={(e) => handleDragOverWithMerge(e, index + 1000, catalog)}
                onDragLeave={handleDragLeave}
                onDrop={(e) => handleDropWithMerge(e, index + 1000, catalog)}
                onDragEnd={() => {
                  setDragIndex(null);
                  handleDragLeave();
                }}
              />
            ))}
          </div>
        </div>
      )}

      <MergeModal
        open={showMergeModal}
        onClose={() => setShowMergeModal(false)}
        catalogA={mergeSource}
        catalogB={mergeTarget}
        onConfirm={onMerge}
      />
    </div>
  );
}

'use client';
import { useState } from 'react';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Slider } from '@/components/ui/slider';
import { PosterRow } from '@/components/shared/PosterRow';
import { Catalog, MyList } from '@/types';
import { GENRE_NAMES, SORT_OPTIONS, LANGUAGES } from '@/lib/constants';
import { Loader2, Wand2, Save, Plus, Trash2, Settings2, X } from 'lucide-react';
import { api } from '@/lib/api';
import { AutocompleteSearch } from '@/components/shared/AutocompleteSearch';
import { generateId } from '@/lib/utils';

const MAX_AI_CATALOG_NAME_LENGTH = 30;

interface CreatorPanelProps {
  onSaveList: (list: MyList) => void;
  onAddCatalog: (catalog: Catalog) => void;
}

interface SelectedItem {
  id: string;
  name: string;
}

export function CreatorPanel({ onSaveList, onAddCatalog }: CreatorPanelProps) {
  const [activeTab, setActiveTab] = useState<string>('ai');

  // AI tab state
  const [prompts, setPrompts] = useState<string[]>(['']);
  const [aiType, setAiType] = useState<'movie' | 'series'>('movie');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiPreviewFilters, setAiPreviewFilters] = useState<Record<string, unknown> | null>(null);
  const [aiPreviewType, setAiPreviewType] = useState<'movie' | 'series'>(aiType);
  const [aiCatalogName, setAiCatalogName] = useState<string>('');
  const [aiRawPrompt, setAiRawPrompt] = useState<string>('');
  const [aiSaved, setAiSaved] = useState(false);

  // Manual tab state
  const [manualName, setManualName] = useState('');
  const [manualType, setManualType] = useState<'movie' | 'series'>('movie');
  const [sortBy, setSortBy] = useState('popularity.desc');
  const [language, setLanguage] = useState('');
  const [genres, setGenres] = useState<string[]>([]);
  const [keywords, setKeywords] = useState<SelectedItem[]>([]);
  const [cast, setCast] = useState<SelectedItem[]>([]);
  const [crew, setCrew] = useState<SelectedItem[]>([]);
  const [voteMin, setVoteMin] = useState(0);
  const [yearFrom, setYearFrom] = useState('');
  const [yearTo, setYearTo] = useState('');
  const [manualLoading, setManualLoading] = useState(false);
  const [manualPreviewFilters, setManualPreviewFilters] = useState<Record<string, unknown> | null>(null);

  const addPrompt = () => setPrompts((p) => [...p, '']);
  const removePrompt = (i: number) => setPrompts((p) => p.filter((_, j) => j !== i));
  const updatePrompt = (i: number, val: string) => setPrompts((p) => p.map((x, j) => (j === i ? val : x)));

  const toggleGenre = (id: string) =>
    setGenres((g) => (g.includes(id) ? g.filter((x) => x !== id) : [...g, id]));
  const toggleKeyword = (item: SelectedItem) =>
    setKeywords((k) => (k.find(x => x.id === item.id) ? k.filter((x) => x.id !== item.id) : [...k, item]));
  const toggleCast = (item: SelectedItem) =>
    setCast((k) => (k.find(x => x.id === item.id) ? k.filter((x) => x.id !== item.id) : [...k, item]));
  const toggleCrew = (item: SelectedItem) =>
    setCrew((k) => (k.find(x => x.id === item.id) ? k.filter((x) => x.id !== item.id) : [...k, item]));

  const handleAiPreview = async () => {
    const validPrompts = prompts.filter((p) => p.trim());
    if (!validPrompts.length) return;
    setAiLoading(true);
    try {
      const prompt = validPrompts[0].trim();
      const result = await api.previewCatalog({ prompt, type: aiType });
      if (result?.filters && typeof result.filters === 'object') {
        setAiPreviewFilters(result.filters);
        setAiPreviewType(result.type === 'series' ? 'series' : 'movie');
        setAiCatalogName(result.name || prompt.slice(0, MAX_AI_CATALOG_NAME_LENGTH));
        setAiRawPrompt(prompt);
      }
    } catch { }
    setAiLoading(false);
  };

  const handleAiSave = () => {
    if (!aiPreviewFilters) return;
    const catalog: Catalog = {
      id: generateId(),
      name: aiCatalogName || 'Catalogo AI',
      raw_prompt: aiRawPrompt,
      type: aiPreviewType,
      source: 'ai',
      filters: aiPreviewFilters,
      emoji: '­ƒñû',
    };
    onAddCatalog(catalog);
    setAiSaved(true);
    setTimeout(() => setAiSaved(false), 3000);
    setPrompts(['']);
    setAiPreviewFilters(null);
    setAiRawPrompt('');
    setAiCatalogName('');
  };

  const buildManualFilters = () => ({
    sort_by: sortBy,
    ...(language && { with_original_language: language }),
    ...(genres.length && { with_genres: genres.join(',') }),
    ...(keywords.length && { with_keywords: keywords.map(k => k.id).join(',') }),
    ...(cast.length && { with_cast: cast.map(c => c.id).join(',') }),
    ...(crew.length && { with_crew: crew.map(c => c.id).join(',') }),
    ...(voteMin > 0 && { 'vote_average.gte': voteMin }),
    ...(yearFrom && { 'primary_release_date.gte': `${yearFrom}-01-01` }),
    ...(yearTo && { 'primary_release_date.lte': `${yearTo}-12-31` }),
  });

  const handleManualPreview = () => {
    setManualPreviewFilters(buildManualFilters());
    setManualLoading(true);
    setTimeout(() => setManualLoading(false), 200);
  };

  const handleManualSave = () => {
    const filters = buildManualFilters();
    const catalog: Catalog = {
      id: generateId(),
      name: manualName || 'Catalogo Personalizzato',
      type: manualType,
      source: 'manual',
      filters,
      emoji: '­ƒÄ¿',
    };
    onAddCatalog(catalog);
  };

  const handleEditManually = () => {
    if (!aiPreviewFilters) return;

    setManualName(aiCatalogName);
    setManualType(aiPreviewType);

    setSortBy((aiPreviewFilters.sort_by as string) || 'popularity.desc');
    setLanguage((aiPreviewFilters.with_original_language as string) || '');

    const parseList = (val: unknown) => {
      if (!val) return [];
      return String(val).replace(/\|/g, ',').split(',').map(s => s.trim()).filter(Boolean);
    };

    setGenres(parseList(aiPreviewFilters.with_genres));

    // Convert flat AI IDs to pill objects
    const mapToPills = (val: unknown, prefix: string) => parseList(val).map(id => ({ id, name: `${prefix}: ${id}` }));

    setKeywords(mapToPills(aiPreviewFilters.with_keywords, 'Keyword'));
    setCast(mapToPills(aiPreviewFilters.with_cast, 'Cast'));
    setCrew(mapToPills(aiPreviewFilters.with_crew, 'Crew'));

    const voteGte = aiPreviewFilters['vote_average.gte'];
    setVoteMin(Number(voteGte) || 0);

    const dateGte = aiPreviewFilters['primary_release_date.gte'] as string;
    if (dateGte) {
      setYearFrom(dateGte.substring(0, 4));
    } else {
      setYearFrom('');
    }

    const dateLte = aiPreviewFilters['primary_release_date.lte'] as string;
    if (dateLte) {
      setYearTo(dateLte.substring(0, 4));
    } else {
      setYearTo('');
    }

    setManualPreviewFilters(aiPreviewFilters);
    setActiveTab('manual');
  };

  const renderPills = (items: SelectedItem[], onRemove: (item: SelectedItem) => void) => (
    <div className="flex flex-wrap gap-1.5 mt-2">
      {items.map(item => (
        <span key={item.id} className="inline-flex items-center gap-1 rounded-full bg-primary/10 text-primary px-3 py-1 text-xs font-bold border border-primary/20">
          {item.name}
          <button onClick={() => onRemove(item)} className="text-primary/70 hover:text-primary ml-0.5 transition-colors">
            <X className="h-3 w-3" />
          </button>
        </span>
      ))}
    </div>
  );

  return (
    <div className="space-y-4">
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="w-full">
          <TabsTrigger value="ai" className="flex-1">
            <Wand2 className="h-4 w-4 mr-2" />
            Catalogo AI
          </TabsTrigger>
          <TabsTrigger value="manual" className="flex-1">
            <Plus className="h-4 w-4 mr-2" />
            Creazione Manuale
          </TabsTrigger>
        </TabsList>

        {/* AI Tab */}
        <TabsContent value="ai" className="space-y-4 mt-4">
          <div>
            <Label className="mb-2 block text-slate-900 dark:text-slate-100 font-bold">Tipo</Label>
            <div className="flex gap-2">
              {(['movie', 'series'] as const).map((t) => (
                <button
                  key={t}
                  onClick={() => setAiType(t)}
                  className={`flex-1 rounded-lg border py-2 text-sm font-bold transition-colors shadow-sm ${aiType === t
                    ? 'border-primary bg-primary/10 text-primary'
                    : 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/40 text-slate-500 dark:text-slate-400 hover:text-primary hover:border-primary/50'
                    }`}
                >
                  {t === 'movie' ? '­ƒÄ¼ Film' : '­ƒô║ Serie'}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <Label className="block text-slate-900 dark:text-slate-100 font-bold">Descrivi il catalogo che vuoi creare</Label>
            {prompts.map((prompt, i) => (
              <div key={i} className="flex gap-2">
                <Input
                  value={prompt}
                  onChange={(e) => updatePrompt(i, e.target.value)}
                  placeholder="es. Film horror italiani degli anni 80..."
                />
                {prompts.length > 1 && (
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => removePrompt(i)}
                    className="shrink-0 text-white/40 hover:text-red-400"
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                )}
              </div>
            ))}
            <Button variant="ghost" size="sm" onClick={addPrompt} className="text-white/50">
              <Plus className="h-4 w-4 mr-1" /> Aggiungi prompt
            </Button>
          </div>

          {aiPreviewFilters && (
            <PosterRow
              filters={aiPreviewFilters}
              type={aiPreviewType}
            />
          )}

          <div className="flex gap-2">
            <Button onClick={handleAiPreview} disabled={aiLoading} className="flex-1">
              {aiLoading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Wand2 className="h-4 w-4 mr-2" />}
              Genera Anteprima
            </Button>
            {aiPreviewFilters && (
              <Button onClick={handleEditManually} variant="secondary" className="flex-1">
                <Settings2 className="h-4 w-4 mr-2" />
                Modifica Manualmente
              </Button>
            )}
            <Button variant="outline" onClick={handleAiSave} disabled={aiSaved || !aiPreviewFilters} className={aiPreviewFilters ? "flex-1" : ""}>
              <Save className="h-4 w-4 mr-2" />
              {aiSaved ? 'Ô£à Aggiunto!' : 'Aggiungi al Profilo'}
            </Button>
          </div>

          {aiSaved && (
            <p className="text-xs text-emerald-400">Catalogo AI aggiunto al profilo.</p>
          )}
        </TabsContent>

        {/* Manual Tab */}
        <TabsContent value="manual" className="space-y-6 mt-4">

          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label htmlFor="manual-name" className="text-slate-900 dark:text-slate-100 font-bold">Nome catalogo</Label>
              <Input
                id="manual-name"
                value={manualName}
                onChange={(e) => setManualName(e.target.value)}
                placeholder="Il mio catalogo"
                className="mt-1"
              />
            </div>
            <div>
              <Label className="text-slate-900 dark:text-slate-100 font-bold">Tipo</Label>
              <div className="flex gap-2 mt-1">
                {(['movie', 'series'] as const).map((t) => (
                  <button
                    key={t}
                    onClick={() => setManualType(t)}
                    className={`flex-1 rounded-md border py-1.5 text-xs font-bold transition-colors ${manualType === t
                      ? 'border-primary bg-primary/10 text-primary'
                      : 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/40 text-slate-500 dark:text-slate-400 hover:text-primary hover:border-primary/50'
                      }`}
                  >
                    {t === 'movie' ? 'Film' : 'Serie'}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <details className="group border border-slate-200 dark:border-slate-700/50 bg-white dark:bg-slate-800 rounded-lg p-4 shadow-sm [&_summary::-webkit-details-marker]:hidden" open>
            <summary className="flex cursor-pointer items-center justify-between font-bold text-slate-900 dark:text-slate-100 select-none">
              Filtri di Base
              <span className="transition group-open:rotate-180">
                <svg fill="none" height="24" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" viewBox="0 0 24 24" width="24"><path d="M6 9l6 6 6-6"></path></svg>
              </span>
            </summary>
            <div className="mt-4 space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label>Ordina per</Label>
                  <Select value={sortBy} onValueChange={setSortBy}>
                    <SelectTrigger className="mt-1">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {SORT_OPTIONS.map((o) => (
                        <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Lingua originale</Label>
                  <Select value={language || '__any'} onValueChange={(v) => setLanguage(v === '__any' ? '' : v)}>
                    <SelectTrigger className="mt-1">
                      <SelectValue placeholder="Qualsiasi" />
                    </SelectTrigger>
                    <SelectContent>
                      {LANGUAGES.map((l) => (
                        <SelectItem key={l.value || '__any'} value={l.value || '__any'}>{l.label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div>
                <Label className="mb-2 block">Voto minimo: {voteMin > 0 ? voteMin.toFixed(1) : 'Qualsiasi'}</Label>
                <div className="px-2">
                  <Slider min={0} max={9} step={0.5} value={[voteMin]} onValueChange={([v]) => setVoteMin(v)} />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label htmlFor="year-from">Anno da</Label>
                  <Input
                    id="year-from"
                    value={yearFrom}
                    onChange={(e) => setYearFrom(e.target.value)}
                    placeholder="es. 2000"
                    className="mt-1"
                    type="number"
                    min="1900"
                    max="2099"
                  />
                </div>
                <div>
                  <Label htmlFor="year-to">Anno a</Label>
                  <Input
                    id="year-to"
                    value={yearTo}
                    onChange={(e) => setYearTo(e.target.value)}
                    placeholder="es. 2024"
                    className="mt-1"
                    type="number"
                    min="1900"
                    max="2099"
                  />
                </div>
              </div>
            </div>
          </details>

          <details className="group border border-slate-200 dark:border-slate-700/50 bg-white dark:bg-slate-800 rounded-lg p-4 shadow-sm [&_summary::-webkit-details-marker]:hidden">
            <summary className="flex cursor-pointer items-center justify-between font-bold text-slate-900 dark:text-slate-100 select-none">
              Generi
              <span className="transition group-open:rotate-180">
                <svg fill="none" height="24" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" viewBox="0 0 24 24" width="24"><path d="M6 9l6 6 6-6"></path></svg>
              </span>
            </summary>
            <div className="mt-4 flex flex-wrap gap-2">
              {Object.entries(GENRE_NAMES).map(([id, name]) => (
                <button
                  key={id}
                  onClick={() => toggleGenre(id)}
                  className={`rounded-full px-3 py-1.5 text-xs font-bold transition-colors shadow-sm ${genres.includes(id)
                    ? 'bg-primary text-white shadow-primary/20'
                    : 'bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-600'
                    }`}
                >
                  {name}
                </button>
              ))}
            </div>
          </details>

          <details className="group border border-slate-200 dark:border-slate-700/50 bg-white dark:bg-slate-800 rounded-lg p-4 shadow-sm [&_summary::-webkit-details-marker]:hidden">
            <summary className="flex cursor-pointer items-center justify-between font-bold text-slate-900 dark:text-slate-100 select-none">
              Parole Chiave & Staff (Ricerca)
              <span className="transition group-open:rotate-180">
                <svg fill="none" height="24" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" viewBox="0 0 24 24" width="24"><path d="M6 9l6 6 6-6"></path></svg>
              </span>
            </summary>
            <div className="mt-4 space-y-5">
              <div>
                <Label className="mb-2 block">Parole Chiave</Label>
                <AutocompleteSearch
                  placeholder="Cerca parole chiave su TMDB..."
                  searchFn={api.searchTmdbKeywords}
                  onSelect={(item) => !keywords.find(k => k.id === item.id) && toggleKeyword(item)}
                />
                {keywords.length > 0 && renderPills(keywords, toggleKeyword)}
              </div>

              <div>
                <Label className="mb-2 block">Attori (Cast)</Label>
                <AutocompleteSearch
                  placeholder="Cerca un attore..."
                  searchFn={api.searchTmdbPeople}
                  onSelect={(item) => !cast.find(k => k.id === item.id) && toggleCast(item)}
                />
                {cast.length > 0 && renderPills(cast, toggleCast)}
              </div>

              <div>
                <Label className="mb-2 block">Registi / Crew</Label>
                <AutocompleteSearch
                  placeholder="Cerca regista o membro dello staff..."
                  searchFn={api.searchTmdbPeople}
                  onSelect={(item) => !crew.find(k => k.id === item.id) && toggleCrew(item)}
                />
                {crew.length > 0 && renderPills(crew, toggleCrew)}
              </div>
            </div>
          </details>

          {/* Preview */}
          {manualPreviewFilters && !manualLoading && (
            <PosterRow filters={manualPreviewFilters} type={manualType} />
          )}

          <div className="flex gap-2">
            <Button onClick={handleManualPreview} disabled={manualLoading} variant="outline" className="flex-1">
              {manualLoading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
              Anteprima
            </Button>
            <Button onClick={handleManualSave} className="flex-1">
              <Save className="h-4 w-4 mr-2" />
              Salva e Aggiungi
            </Button>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

'use client';
import { useState, useMemo } from 'react';
import { Preset, Profile } from '@/types';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { TypeBadge } from '@/components/shared/TypeBadge';
import { PosterRow } from '@/components/shared/PosterRow';
import { Check, Search } from 'lucide-react';

interface ExplorePanelProps {
  presets: Preset[];
  categories: string[];
  profile: Profile;
  onTogglePreset: (presetId: string) => void;
}

export function ExplorePanel({ presets, categories, profile, onTogglePreset }: ExplorePanelProps) {
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('Tutti');
  const [showSearch, setShowSearch] = useState(false);

  const selectedPresets = profile.raw_ui_state.selectedPresets;

  const filtered = useMemo(() => {
    let list = presets;
    if (selectedCategory !== 'Tutti') {
      list = list.filter((p) => p.category === selectedCategory);
    }
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter((p) => p.name.toLowerCase().includes(q));
    }
    return list;
  }, [presets, selectedCategory, search]);

  const allCategories = ['Tutti', ...categories];

  return (
    <div className="space-y-4">
      {/* Search toggle */}
      <div className="flex items-center gap-2">
        <div className="flex-1 flex gap-2 overflow-x-auto pb-1 scrollbar-thin">
          {allCategories.map((cat) => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`shrink-0 rounded-full px-4 py-1.5 text-xs font-medium transition-all ${selectedCategory === cat
                ? 'bg-primary text-white shadow-md shadow-primary/20'
                : 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:text-primary transition-colors border border-slate-200 dark:border-slate-700'
                }`}
            >
              {cat}
            </button>
          ))}
        </div>
        <Button
          variant="ghost"
          size="icon"
          className="h-8 w-8 shrink-0 text-slate-500 hover:text-primary"
          onClick={() => setShowSearch(!showSearch)}
        >
          <Search className="h-4 w-4" />
        </Button>
      </div>

      {showSearch && (
        <Input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Cerca cataloghi..."
          autoFocus
          className="bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700"
        />
      )}

      {/* Preset grid ÔÇö always shows posters */}
      <div className="grid gap-8">
        {filtered.length === 0 && (
          <div className="py-8 text-center text-sm text-slate-400 dark:text-slate-500">
            Nessun catalogo trovato
          </div>
        )}
        {filtered.map((preset) => {
          const isSelected = selectedPresets.includes(preset.id);

          return (
            <div key={preset.id} className="w-full min-w-0 p-0 flex flex-col group bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700/50 shadow-sm overflow-hidden">
              <div className="flex flex-col p-4 bg-slate-50 dark:bg-slate-800/40 border-b border-slate-100 dark:border-slate-700/50 relative z-10">
                <div className="flex items-center justify-between gap-3">
                  <div className="flex items-center gap-2 min-w-0 flex-1">
                    <span className="text-xl shrink-0 leading-none">{preset.emoji ?? '­ƒôï'}</span>
                    <h4 className="flex-1 truncate text-sm font-bold text-slate-900 dark:text-slate-100">{preset.name}</h4>
                    <div className="shrink-0">
                      <TypeBadge type={preset.type as 'movie' | 'series' | 'both'} />
                    </div>
                    {preset.category && (
                      <Badge variant="secondary" className="hidden sm:inline-flex text-[10px] px-1.5 py-0 shrink-0 bg-primary/10 text-primary hover:bg-primary/20 border-0">
                        {preset.category}
                      </Badge>
                    )}
                  </div>

                  <Button
                    size="sm"
                    variant={isSelected ? 'secondary' : 'default'}
                    onClick={() => onTogglePreset(preset.id)}
                    className={`h-8 px-3 text-xs shrink-0 ml-auto font-bold ${isSelected ? 'bg-emerald-500/10 text-emerald-600 hover:bg-emerald-500/20' : 'bg-primary text-white hover:brightness-110'
                      }`}
                  >
                    {isSelected ? (
                      <>
                        <Check className="h-3.5 w-3.5 mr-1" />
                        Aggiunto
                      </>
                    ) : (
                      'Aggiungi'
                    )}
                  </Button>
                </div>
                {preset.description && (
                  <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 line-clamp-2">{preset.description}</p>
                )}
              </div>

              {/* Always-visible poster row */}
              <div className="w-full min-w-0 overflow-hidden bg-white dark:bg-slate-800 p-2">
                <PosterRow presetId={preset.id} type={preset.type} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

'use client';
import { useState } from 'react';
import { Profile } from '@/types';
import { Input } from '@/components/ui/input';

interface ProfileManagerProps {
  profiles: Profile[];
  editingProfileId: string;
  activeProfileId: string;
  onSelectEditing: (id: string) => void;
  onSetActive: (id: string) => void;
  onAdd: (name: string) => void;
  onRename: (id: string, name: string) => void;
}

export function ProfileManager({
  profiles,
  editingProfileId,
  activeProfileId,
  onSelectEditing,
  onSetActive,
  onAdd,
  onRename,
}: ProfileManagerProps) {
  const [adding, setAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [renamingId, setRenamingId] = useState<string | null>(null);
  const [renameValue, setRenameValue] = useState('');

  const handleAdd = () => {
    if (!newName.trim()) return;
    onAdd(newName.trim());
    setNewName('');
    setAdding(false);
  };

  const commitRename = () => {
    if (renamingId && renameValue.trim()) {
      onRename(renamingId, renameValue.trim());
    }
    setRenamingId(null);
    setRenameValue('');
  };

  return (
    <section className="flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <h2 className="text-slate-900 dark:text-slate-100 text-xl font-bold">I tuoi Profili</h2>
          <span className="bg-primary/20 text-primary text-xs font-bold px-2 py-0.5 rounded-full">
            {profiles.length} Profil{profiles.length !== 1 ? 'i' : 'o'}
          </span>
        </div>

        {adding ? (
          <div className="flex gap-2">
            <Input
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              placeholder="Nome profilo..."
              onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
              autoFocus
              className="h-9 w-32 md:w-48 bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700"
            />
            <button onClick={handleAdd} className="flex items-center justify-center rounded-lg h-9 w-9 bg-primary text-white hover:brightness-110">
              <span className="material-symbols-outlined text-sm">check</span>
            </button>
            <button onClick={() => setAdding(false)} className="flex items-center justify-center rounded-lg h-9 w-9 bg-slate-200 dark:bg-slate-700 text-slate-500 hover:text-slate-700 dark:hover:text-slate-300">
              <span className="material-symbols-outlined text-sm">close</span>
            </button>
          </div>
        ) : (
          <button
            onClick={() => setAdding(true)}
            className="flex items-center gap-2 cursor-pointer justify-center rounded-lg h-9 px-4 bg-primary text-slate-100 text-sm font-bold hover:brightness-110 transition-all"
          >
            <span className="material-symbols-outlined text-sm">add</span>
            <span>Nuovo</span>
          </button>
        )}
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-4">
        {profiles.map((profile) => {
          const isActive = activeProfileId === profile.id;
          const isEditing = editingProfileId === profile.id;

          let icon = profile.name.charAt(0).toUpperCase();
          if (profile.name.startsWith('­ƒÅá')) icon = 'home';
          else if (profile.name.startsWith('­ƒÄ¼') || profile.name.startsWith('­ƒô║') || profile.name.startsWith('­ƒÄ¡')) icon = 'movie';

          if (isActive) {
            return (
              <div
                key={profile.id}
                onClick={() => onSelectEditing(profile.id)}
                className={`flex flex-col items-center p-4 rounded-xl border-2 cursor-pointer gap-3 relative transition-all ${isEditing ? 'border-primary bg-primary/5' : 'border-primary/50 bg-primary/5 hover:border-primary'}`}
              >
                <div className="size-12 rounded-full bg-primary text-white flex items-center justify-center">
                  {icon.length > 2 ? <span className="material-symbols-outlined">{icon}</span> : icon}
                </div>
                <div className="text-center w-full">
                  <p className="text-sm font-bold text-slate-900 dark:text-slate-100 truncate w-full">{profile.name}</p>
                  <p className="text-[10px] text-emerald-500 font-bold uppercase mt-0.5">Attivo</p>
                </div>
                <div className="absolute top-2 right-2">
                  <span className="material-symbols-outlined text-primary text-sm">check_circle</span>
                </div>
              </div>
            );
          }

          return (
            <div
              key={profile.id}
              onClick={() => onSelectEditing(profile.id)}
              className={`flex flex-col items-center p-4 rounded-xl border border-slate-200 dark:border-slate-700/50 bg-slate-100 dark:bg-slate-800/40 gap-3 hover:border-primary/50 transition-all cursor-pointer ${isEditing ? 'ring-2 ring-primary/30 border-primary/50' : ''}`}
            >
              <div className="size-12 rounded-full bg-slate-200 dark:bg-slate-700 text-slate-500 flex items-center justify-center font-bold">
                {icon.length > 2 ? <span className="material-symbols-outlined">{icon}</span> : icon}
              </div>
              <div className="text-center w-full">
                <p className="text-sm font-bold text-slate-900 dark:text-slate-100 truncate w-full">{profile.name}</p>
                <button
                  onClick={(e) => { e.stopPropagation(); onSetActive(profile.id); }}
                  className="mt-2 px-3 py-1 bg-slate-200 dark:bg-slate-700 hover:bg-primary hover:text-white text-[10px] font-bold rounded-lg transition-all"
                >
                  ATTIVA
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
}

'use client';
import { Profile, ProfileTemplate, Pillar } from '@/types';
import { AutocompleteSearch } from '@/components/shared/AutocompleteSearch';
import { api } from '@/lib/api';
import { Settings, Check, Pencil, Trash2, X, Plus } from 'lucide-react';

interface ProfileSettingsPanelProps {
    profile: Profile;
    profileTemplates: ProfileTemplate[];
    onApplyTemplate: (template: ProfileTemplate) => void;
    onUpdateProfile: (id: string, updates: Partial<Profile>) => void;
    onSetActive: (id: string) => void;
    onRename: (id: string, name: string) => void;
    onRemove: (id: string) => void;
    isActive: boolean;
    startRename: () => void;
}

export function ProfileSettingsPanel({
    profile,
    profileTemplates,
    onApplyTemplate,
    onUpdateProfile,
    onSetActive,
    onRename,
    onRemove,
    isActive,
    startRename
}: ProfileSettingsPanelProps) {
    const profileKeywords: Pillar[] = profile?.settings?.manualPillars ?? [];
    const suggestedKeywords: Pillar[] = profile?.settings?.suggestedPillars ?? [];

    const handleAddPillar = (pillar: Pillar) => {
        if (profileKeywords.find((p) => String(p.id) === String(pillar.id))) return;
        const newPillars = [...profileKeywords, pillar];
        onUpdateProfile(profile.id, {
            settings: { ...profile.settings, manualPillars: newPillars },
        });
    };

    const handleRemovePillar = (pillarId: string) => {
        const newPillars = profileKeywords.filter((p) => String(p.id) !== String(pillarId));
        onUpdateProfile(profile.id, {
            settings: { ...profile.settings, manualPillars: newPillars },
        });
    };

    return (
        <div className="flex flex-col rounded-xl border-2 border-primary/30 bg-white/5 dark:bg-slate-800/60 overflow-hidden shadow-lg shadow-primary/5 mt-2">
            <div className="px-6 py-4 border-b border-primary/10 flex items-center justify-between bg-primary/5">
                <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-primary">settings</span>
                    <span className="text-sm font-bold">Impostazioni Profilo: <span className="text-primary">{profile.name}</span></span>
                </div>
                <div className="flex items-center gap-2">
                    {!isActive && (
                        <button onClick={() => onSetActive(profile.id)} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-primary text-white text-xs font-bold shadow-md hover:brightness-110 transition-all">
                            <span className="material-symbols-outlined text-sm">check</span>
                            <span>Attiva Profilo</span>
                        </button>
                    )}
                    <button onClick={startRename} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-slate-100 dark:bg-slate-700 hover:bg-primary/20 text-slate-700 dark:text-slate-200 text-xs font-bold transition-all">
                        <span className="material-symbols-outlined text-sm">edit</span>
                        <span>Rinomina</span>
                    </button>
                    <button onClick={() => onRemove(profile.id)} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-rose-500/10 hover:bg-rose-500 hover:text-white text-rose-500 text-xs font-bold transition-all">
                        <span className="material-symbols-outlined text-sm">delete</span>
                        <span>Elimina</span>
                    </button>
                </div>
            </div>

            <div className="p-6 flex flex-col gap-8 bg-slate-100 dark:bg-transparent">
                {/* Modelli Suggeriti Section */}
                {profileTemplates.length > 0 && (
                    <div className="flex flex-col gap-4">
                        <div className="flex items-center justify-between cursor-pointer group">
                            <div className="flex items-center gap-3 text-primary">
                                <span className="material-symbols-outlined">auto_awesome</span>
                                <p className="text-sm font-black uppercase tracking-widest">Modelli Suggeriti</p>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                            {profileTemplates.slice(0, 3).map((tpl) => (
                                <div
                                    key={tpl.id}
                                    onClick={() => onApplyTemplate(tpl)}
                                    className="p-4 rounded-lg bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:border-primary transition-all cursor-pointer"
                                >
                                    <p className="text-slate-900 dark:text-slate-100 font-bold text-sm">{tpl.name}</p>
                                    <p className="text-slate-500 dark:text-slate-400 text-xs mt-1">{tpl.description}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Parole Chiave Section */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-3 text-primary">
                        <span className="material-symbols-outlined">key</span>
                        <p className="text-sm font-black uppercase tracking-widest">Parole Chiave</p>
                    </div>
                    <div className="flex flex-col gap-3">
                        <p className="text-xs text-slate-500 dark:text-slate-400 leading-relaxed">
                            Vincola le raccomandazioni del profilo <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-primary/10 text-primary font-bold"><span className="material-symbols-outlined text-[10px]">home</span> {profile.name}</span> a temi specifici. Troppi vincoli possono ridurre i risultati.
                        </p>

                        <div className="flex flex-wrap gap-2 mb-1">
                            {profileKeywords.map((p) => (
                                <span
                                    key={p.id}
                                    className="inline-flex items-center gap-1 rounded bg-primary/20 text-primary px-3 py-1.5 text-xs font-bold"
                                >
                                    {p.type === 'genre' ? '­ƒÄ¡ ' : p.type === 'country' ? '­ƒîì ' : ''} {p.name}
                                    <button
                                        onClick={() => handleRemovePillar(String(p.id))}
                                        className="ml-1 text-primary hover:text-primary/70 transition-colors"
                                    >
                                        <X className="h-3 w-3" />
                                    </button>
                                </span>
                            ))}
                        </div>

                        <div className="relative text-black dark:text-white">
                            <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 z-10 pointer-events-none">search</span>
                            <div className="w-full relative [&_input]:pl-10 [&_input]:py-3 [&_input]:bg-white dark:[&_input]:bg-slate-800 [&_input]:border-slate-200 dark:[&_input]:border-slate-700 [&_input]:rounded-lg [&_input]:text-sm">
                                <AutocompleteSearch
                                    placeholder="Aggiungi interessi (es. Anime, Sci-Fi...)"
                                    searchFn={api.searchTmdbKeywords}
                                    onSelect={(item) => handleAddPillar({ type: 'keyword', id: String(item.id), name: item.name })}
                                />
                            </div>
                        </div>

                        {suggestedKeywords.filter((sp) => !profileKeywords.find((mp) => String(mp.id) === String(sp.id))).length > 0 && (
                            <div className="pt-2">
                                <p className="text-[11px] text-slate-400 mb-2">Suggeriti per te</p>
                                <div className="flex flex-wrap gap-2">
                                    {suggestedKeywords
                                        .filter((sp) => !profileKeywords.find((mp) => String(mp.id) === String(sp.id)))
                                        .map((p) => (
                                            <button
                                                key={p.id}
                                                onClick={() => handleAddPillar(p)}
                                                className="inline-flex items-center gap-1 rounded-full border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 px-3 py-1 text-[11px] font-medium hover:border-primary transition-colors"
                                            >
                                                <Plus className="h-3 w-3" />
                                                {p.name}
                                            </button>
                                        ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

