        filters: {
          merge: { catalogs: [catalogA.id, catalogB.id], strategy },
        },
        type: catalogA.type,
      });
      setPreviewItems(data.items ?? []);
    } catch { }
    setLoading(false);
  };

  const handleAiNaming = async () => {
    if (!catalogA || !catalogB) return;
