'use client';
import { useState, useEffect, useRef, useCallback } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { api } from '@/lib/api';
import { ExternalLink, Loader2, CheckCircle2 } from 'lucide-react';

interface TraktAuthModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess: (token: string, refreshToken: string) => void;
}

export function TraktAuthModal({ open, onClose, onSuccess }: TraktAuthModalProps) {
  const [userCode, setUserCode] = useState('');
  const [verificationUrl, setVerificationUrl] = useState('');
  const [deviceCode, setDeviceCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [polling, setPolling] = useState(false);
  const [countdown, setCountdown] = useState(0);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  const countdownRef = useRef(countdown);
  countdownRef.current = countdown;

  const onSuccessRef = useRef(onSuccess);
  onSuccessRef.current = onSuccess;
  const onCloseRef = useRef(onClose);
  onCloseRef.current = onClose;

  useEffect(() => {
    if (!open) return;
    setLoading(true);
    setError('');
    setSuccess(false);
    setPolling(false);
    api
      .traktDeviceCode()
      .then((data) => {
        setUserCode(data.user_code ?? '');
        setVerificationUrl(data.verification_url ?? 'https://trakt.tv/activate');
        setDeviceCode(data.device_code ?? '');
        setCountdown(data.expires_in ?? 600);
        setPolling(true);
      })
      .catch(() => setError('Errore nella connessione a Trakt'))
      .finally(() => setLoading(false));
  }, [open]);

  // Countdown timer
  useEffect(() => {
    if (!polling) return;
    const timer = setInterval(() => {
      setCountdown((c) => {
        if (c <= 1) {
          clearInterval(timer);
          return 0;
        }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [polling]);

  // Polling for token ÔÇö uses refs so it doesn't restart on countdown/callback changes
  useEffect(() => {
    if (!polling || !deviceCode) return;
    const interval = setInterval(async () => {
      if (countdownRef.current <= 0) {
        clearInterval(interval);
        return;
      }
      try {
        const data = await api.traktDeviceToken(deviceCode);
        if (data.access_token) {
          setSuccess(true);
          setPolling(false);
          onSuccessRef.current(data.access_token, data.refresh_token ?? '');
          setTimeout(() => onCloseRef.current(), 1500);
        }
      } catch {}
    }, 5000);
    return () => clearInterval(interval);
  }, [polling, deviceCode]);

  const mins = Math.floor(countdown / 60);
  const secs = countdown % 60;
  const progress = countdown > 0 ? (countdown / 600) * 100 : 0;

  return (
    <Dialog open={open} onOpenChange={() => onClose()}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <span className="flex h-8 w-8 items-center justify-center rounded-lg bg-red-500/20 text-red-400">­ƒÄ¼</span>
            Connetti Trakt
          </DialogTitle>
          <DialogDescription>
            Autorizza YACA ad accedere al tuo account Trakt
          </DialogDescription>
        </DialogHeader>

        {loading && (
          <div className="flex flex-col items-center py-8 gap-3">
            <Loader2 className="h-8 w-8 animate-spin text-[#8a5aeb]" />
            <p className="text-sm text-white/50">Connessione a Trakt...</p>
          </div>
        )}

        {success && (
          <div className="flex flex-col items-center py-8 gap-3">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-emerald-500/20">
              <CheckCircle2 className="h-8 w-8 text-emerald-400" />
            </div>
            <p className="text-white font-semibold text-lg">Trakt connesso!</p>
            <p className="text-sm text-white/50">Reindirizzamento in corso...</p>
          </div>
        )}

        {!loading && !success && userCode && (
          <div className="space-y-5">
            <div className="relative rounded-xl bg-gradient-to-br from-[#8a5aeb]/10 to-red-500/10 border border-white/10 p-6 text-center overflow-hidden">
              <p className="text-xs text-white/50 mb-3 uppercase tracking-wider font-medium">Il tuo codice di attivazione</p>
              <p className="text-4xl font-mono font-bold tracking-[0.3em] text-[#8a5aeb]">{userCode}</p>
              <div className="mt-4 flex items-center justify-center gap-2">
                <div className="h-1.5 flex-1 max-w-[200px] rounded-full bg-white/10 overflow-hidden">
                  <div
                    className="h-full rounded-full bg-gradient-to-r from-[#8a5aeb] to-red-400 transition-all duration-1000"
                    style={{ width: `${progress}%` }}
                  />
                </div>
                <span className="text-xs text-white/40 font-mono tabular-nums">
                  {mins}:{secs.toString().padStart(2, '0')}
                </span>
              </div>
            </div>

            <div className="rounded-xl bg-white/5 border border-white/10 p-4">
              <ol className="space-y-3 text-sm text-white/70">
                <li className="flex gap-3 items-start">
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#8a5aeb]/20 text-xs font-bold text-[#8a5aeb]">1</span>
                  <span>Vai su <strong className="text-white">{verificationUrl}</strong></span>
                </li>
                <li className="flex gap-3 items-start">
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#8a5aeb]/20 text-xs font-bold text-[#8a5aeb]">2</span>
                  <span>Inserisci il codice sopra</span>
                </li>
                <li className="flex gap-3 items-start">
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#8a5aeb]/20 text-xs font-bold text-[#8a5aeb]">3</span>
                  <span>Autorizza YACA su Trakt</span>
                </li>
              </ol>
            </div>

            <a href={verificationUrl} target="_blank" rel="noopener noreferrer">
              <Button className="w-full bg-red-500/20 border-red-500/30 text-red-300 hover:bg-red-500/30" variant="outline">
                <ExternalLink className="h-4 w-4 mr-2" />
                Apri Trakt.tv
              </Button>
            </a>

            {polling && (
              <div className="flex items-center justify-center gap-2 text-xs text-white/50 py-1">
                <Loader2 className="h-3 w-3 animate-spin text-[#8a5aeb]" />
                In attesa di autorizzazione...
              </div>
            )}

            {error && (
              <div className="rounded-lg bg-red-500/10 border border-red-500/20 p-3">
                <p className="text-xs text-red-400 text-center">{error}</p>
              </div>
            )}
          </div>
        )}

        <div className="flex justify-end">
          <Button variant="ghost" onClick={onClose} className="text-white/50 hover:text-white">Annulla</Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';
import { Catalog } from '@/types';

interface CatalogItemProps {
  catalog: Catalog;
  onRemove?: () => void;
  dragHandleProps?: React.HTMLAttributes<HTMLSpanElement>;
  isDragging?: boolean;
  isMergeTarget?: boolean;
  onDragStart?: React.DragEventHandler;
  onDragOver?: React.DragEventHandler;
  onDragLeave?: React.DragEventHandler;
  onDrop?: React.DragEventHandler;
  onDragEnd?: React.DragEventHandler;
}

export function CatalogItem({
  catalog,
  onRemove,
  isDragging,
  isMergeTarget,
  onDragStart,
  onDragOver,
  onDragLeave,
  onDrop,
  onDragEnd,
}: CatalogItemProps) {
  const isPreset = catalog.source === 'preset';
  const filterCount = catalog.filters ? Object.keys(catalog.filters).length : 0;

  let sourceLabel = isPreset ? 'Preset' : (catalog.source === 'mylist' ? 'My List' : 'Creato');
  let sourceIcon = isPreset ? 'auto_awesome' : (catalog.source === 'mylist' ? 'list' : 'auto_fix');

  return (
    <div
      draggable
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={onDrop}
      onDragEnd={onDragEnd}
      className={`group relative flex flex-col bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700/50 shadow-sm hover:shadow-xl hover:shadow-primary/5 hover:border-primary/30 transition-all p-5 cursor-grab active:cursor-grabbing ${isDragging ? 'opacity-50 scale-95' : ''
        } ${isMergeTarget
          ? 'scale-105 ring-4 ring-primary ring-offset-4 ring-offset-background-light dark:ring-offset-background-dark bg-primary/10 z-10 animate-pulse'
          : ''
        }`}
    >
      <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity rounded-2xl pointer-events-none"></div>

      <div className="flex items-start justify-between mb-4 relative z-10">
        <div className="flex gap-4 items-center">
          <div className="size-12 rounded-xl bg-primary/10 text-primary flex items-center justify-center shadow-inner">
            <span className="text-2xl">{catalog.emoji ?? '­ƒôï'}</span>
          </div>
          <div>
            <h3 className="font-bold text-slate-900 dark:text-slate-100 text-lg leading-tight line-clamp-1">{catalog.name}</h3>
            <span className="inline-flex items-center gap-1 mt-1 px-2 py-0.5 rounded-md bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 text-[10px] font-bold uppercase tracking-wider">
              <span className="material-symbols-outlined text-[10px]">{sourceIcon}</span> {sourceLabel}
            </span>
          </div>
        </div>
        {onRemove && (
          <button
            onClick={onRemove}
            className="text-slate-400 hover:text-rose-500 transition-colors p-2 -mr-2 -mt-2"
          >
            <span className="material-symbols-outlined text-[20px]">delete</span>
          </button>
        )}
      </div>

      <p className="text-sm text-slate-500 dark:text-slate-400 line-clamp-2 mb-4 relative z-10">
        {catalog.raw_prompt || 'Catalogo basato su filtri e preferenze per risultati personalizzati.'}
      </p>

      <div className="mt-auto pt-4 border-t border-slate-100 dark:border-slate-700/50 flex items-center justify-between relative z-10">
        <div className="flex items-center gap-1.5 text-xs font-semibold text-slate-500 dark:text-slate-400">
          <span className="material-symbols-outlined text-sm">{catalog.type === 'movie' ? 'movie' : 'tv'}</span>
          {filterCount} Filtr{filterCount !== 1 ? 'i' : 'o'}
        </div>
        <button className="flex items-center gap-1 text-xs font-bold text-primary hover:text-primary/70 transition-colors">
          Personalizza <span className="material-symbols-outlined text-sm">arrow_forward</span>
        </button>
      </div>
    </div>
  );
}

